import { z } from 'zod';
import { guild } from '@shardworks/nexus-core';
import { tool } from '@shardworks/tools-apparatus';
import type { ClerkApi } from '../types.ts';

/**
 * Build a task XML body from structured fields, matching the task-manifest format.
 */
function buildTaskXml(params: {
  name: string;
  action: string;
  files?: string;
  verify?: string;
  done?: string;
}): string {
  // Generate a simple id based on timestamp to ensure uniqueness
  const id = `t-${Date.now().toString(36)}`;
  const lines: string[] = [];
  lines.push(`<task id="${id}">`);
  lines.push(`    <name>${params.name}</name>`);
  if (params.files) {
    lines.push(`    <files>${params.files}</files>`);
  }
  lines.push(`    <action>${params.action}</action>`);
  if (params.verify) {
    lines.push(`    <verify>${params.verify}</verify>`);
  }
  if (params.done) {
    lines.push(`    <done>${params.done}</done>`);
  }
  lines.push(`</task>`);
  return lines.join('\n');
}

export default tool({
  name: 'piece-add',
  description: 'Add a new piece (atomic task) to a mandate for sequential execution',
  instructions:
    'Creates a new piece writ as a child of the specified mandate. The piece is created ' +
    'in open status and will be picked up by the implement-loop engine after the current ' +
    'piece session completes. The body is structured as a <task> XML element matching the ' +
    'task-manifest format used by the spec writer. ' +
    'Requires an explicit mandateId — the mandate must be in new, open, or stuck status.',
  callableBy: ['anima', 'patron'],
  params: {
    mandateId: z.string().describe('ID of the parent mandate writ'),
    name: z.string().describe('Short name for the task'),
    action: z.string().describe('Description of what to do'),
    files: z.string().optional().describe('Predicted affected files (orientation hint)'),
    verify: z.string().optional().describe('Command to verify completion'),
    done: z.string().optional().describe('Criterion for task completion'),
  },
  permission: 'write',
  handler: async (params) => {
    const clerk = guild().apparatus<ClerkApi>('clerk');
    const body = buildTaskXml(params);

    return clerk.post({
      type: 'piece',
      title: params.name,
      body,
      parentId: params.mandateId,
    });
  },
});

import { z } from 'zod';
import { guild } from '@shardworks/nexus-core';
import { tool } from '@shardworks/tools-apparatus';
import type { ClerkApi } from '../types.ts';

export default tool({
  name: 'commission-post',
  description: 'Post a new commission, creating a writ in open or new (draft) status',
  instructions:
    'Creates a new writ. By default the writ is placed in open status and enters the queue ' +
    'immediately. Pass draft: true to create the writ in new (draft) status instead — draft ' +
    'writs are held out of the queue until explicitly published with writ-publish. ' +
    'The writ type must be a type declared in the guild config, or the built-in type "mandate". ' +
    'If type is omitted, the guild\'s configured default type is used (defaults to "mandate"). ' +
    'Use parentId to create this writ as a child of an existing writ. The parent must be in ' +
    'new or open status.',
  params: {
    title: z.string().describe('Short human-readable title describing the work'),
    body: z.string().describe('Detail text or description'),
    type: z.string().optional().describe('Writ type (default: guild defaultType or "mandate")'),
    codex: z.string().optional().describe('Target codex name'),
    draft: z
      .boolean()
      .optional()
      .describe(
        'When true, create the writ in new (draft) status instead of open. ' +
        'Draft writs must be published before they enter the execution queue.',
      ),
    parentId: z
      .string()
      .optional()
      .describe(
        'Create this writ as a child of the specified parent writ. ' +
        'The parent must be in new or open status.',
      ),
  },
  permission: 'write',
  handler: async (params) => {
    const clerk = guild().apparatus<ClerkApi>('clerk');
    return clerk.post({
      title: params.title,
      body: params.body,
      type: params.type,
      codex: params.codex,
      draft: params.draft,
      parentId: params.parentId,
    });
  },
});

